```bash
curl -X POST https://tasks.internal.beacon.studio/api/v1/tasks \
  -H "Authorization: Bearer $INTERNAL_TASKS_TOKEN" \
  -H "Content-Type: application/json" \
  -d '{
    "title": "MemorySync: Async offload for /v1/memory/snapshot",
    "tags": ["memorysync-perf", "performance", "codexai-launch"],
    "priority": "medium",
    "description": "POST /v1/memory/snapshot averaging ~739ms due to synchronous serialisation of ~18KB session state blobs. Recommendation: offload to async worker, return 202 Accepted immediately, emit memory.snapshot.complete webhook on completion. Aligns with planner-executor model. Flagged in worker_session_20260223_0926.",
    "source_session": "worker_session_20260223_0926",
    "assigned_to": "echo",
    "due_date": null
  }'
```

